// 1. Webhook'tan gelen veriyi al
const inputItem = $input.first();
let body = inputItem.json.body;

// 2. Gelen body string ise (text/plain durumunda) JSON'a çevir
if (typeof body === 'string') {
    try {
        body = JSON.parse(body);
    } catch (error) {
        throw new Error("Gelen veri JSON formatında değil! Lütfen webhook gönderim formatını kontrol edin.");
    }
}

// 3. Tarihleri Al
const startDateRaw = body.start || body.start_date;
const endDateRaw = body.end || body.end_date;
const companyId = body.company_id || body.companyId;
const email = body.email || body.target_email;

// 4. Supabase için Tarih Formatlama (ISO 8601)
// Başlangıç: Günün ilk saniyesi (00:00:00)
// Bitiş: Günün son saniyesi (23:59:59) - Böylece o gün kesilen fişler de dahil olur.

// Eğer tarih zaten T içeriyorsa (örn: 2025-10-01T14:00:00) olduğu gibi bırak, yoksa saat ekle.
const dbStartDate = startDateRaw.includes('T') ? startDateRaw : `${startDateRaw}T00:00:00`;
const dbEndDate = endDateRaw.includes('T') ? endDateRaw : `${endDateRaw}T23:59:59`;

// 5. Dosya ismi için temiz tarih (Sadece YYYY-MM-DD)
const fileStartDate = dbStartDate.split('T')[0];
const fileEndDate = dbEndDate.split('T')[0];

return {
  json: {
    // İşlenecek Temel Veriler
    company_id: companyId,
    target_email: email,

    // Supabase Sorgusu İçin Hazırlanmış Tarihler
    db_query_start: dbStartDate,
    db_query_end: dbEndDate,

    // Rapor/Dosya İsmi İçin Veriler
    generated_filename: `Fiş Fatura_Rapor_${fileStartDate}_${fileEndDate}.xlsx`,

    // Rapor Yapılandırması
    config: {
        sourceSpreadsheetId: "12jM6rOFPFKsuEbOfE532v9cuNqTGd4KY69ixqRgoquA",
        templateFileId: "1j8xbs5q_v2NfPk1V0Mmx0oQrSa-11xL_kMXbafKYIMA"
    }
  }
};

// -----------------------------------------------------------
// DÖNGÜ İÇİN YAZMA VERİSİNİ HAZIRLA (V5 - İsim Düzeltildi)
// -----------------------------------------------------------

// Yardımcı Fonksiyon: Düğüm ismini hem normal hem de "1" ekli haliyle arar.
function getSafeNodeData(nodeName) {
    try {
        // 1. Tam ismi dene
        return $(nodeName).item.json;
    } catch (e) {
        try {
            // 2. Sonuna "1" ekleyip dene
            return $(nodeName + "1").item.json;
        } catch (e2) {
            return null; // Bulunamazsa null dön
        }
    }
}

try {
    // 1. VERİLERİ GÜVENLİ ŞEKİLDE ÇEK

    // A. Sheet ID (Input'tan gelir - Yeni Sekme Oluştur)
    const sheetData = $input.item.json;

    // B. Kullanıcı Bilgisi ('kullanıcı al' veya 'Get a row')
    let userData = getSafeNodeData("kullanıcı al");
    if (!userData) userData = getSafeNodeData("Get a row"); 

    // C. Fiş Verisi (DİKKAT: İsim "Gurupları" olarak güncellendi)
    const groupData = getSafeNodeData("Gurupları Döngüye Al");

    // -------------------------------------------------------
    // HATA KONTROLÜ
    // -------------------------------------------------------
    if (!groupData) throw new Error("KRİTİK HATA: 'Gurupları Döngüye Al' düğümü bulunamadı! İsmi kopyala-yapıştır ile güncelledim.");
    if (!userData) console.log("UYARI: Kullanıcı verisi bulunamadı, 'Bilinmeyen' kullanılacak.");

    // 2. VERİLERİ İŞLE
    const newSheetId = sheetData.replies?.[0]?.duplicateSheet?.properties?.sheetId;
    if (newSheetId === undefined) throw new Error("Sheet ID bulunamadı. 'Yeni Sekme Oluştur' düğümü düzgün çalıştı mı?");

    const rawRecords = groupData.rows || [];

    // Kullanıcı Adını Belirle
    let realUserName = "Bilinmeyen Kullanıcı";
    if (userData) {
        if (userData.full_name) realUserName = userData.full_name;
        else if (userData.ad_soyad) realUserName = userData.ad_soyad;
    } else if (groupData.meta?.kullanici) {
        realUserName = groupData.meta.kullanici;
    }

    // Başlık Metinleri
    const metaKart = groupData.meta?.kart || 'Kart';
    const metaProje = groupData.meta?.proje || 'Proje';
    const headerText = `${realUserName} - ${metaKart} - ${metaProje}`;

    // Evrak No
    const companyId = (rawRecords.length > 0 && rawRecords[0].company_id) ? rawRecords[0].company_id : "00";
    const randomSeq = Date.now().toString().slice(-5);
    const evrakNo = `${companyId}${randomSeq}`;

    // Tarih Formatlayıcı
    function formatDateTR(dateStr) {
        if (!dateStr) return "";
        let cleanStr = dateStr.toString().replace("'", "").split("T")[0];
        const parts = cleanStr.split('-');
        if (parts.length === 3) return `${parts[2]}.${parts[1]}.${parts[0]}`;
        return cleanStr;
    }

    // 3. SATIRLARI OLUŞTUR (Consolidation)
    const mergedMap = {};
    for (const r of rawRecords) {
        if (r.ocr_detaylari && Array.isArray(r.ocr_detaylari)) {
            r.ocr_detaylari.forEach(detay => {
                const key = `${r.fis_no}_${detay.KDVOrani}_${detay.kategori || "Genel"}_${r.tarih}`;
                if (!mergedMap[key]) {
                    mergedMap[key] = {
                        ...r,
                        "Açıklama": detay.kategori || r.kategori || "Genel",
                        "Matrah": parseFloat(detay.Matrah || 0),
                        "KDV Oranı": detay.KDVOrani,
                        "KDV Tutarı": parseFloat(detay.KDVTutari || 0),
                        "Toplam Tutar": parseFloat(detay.Tutar_KDVDahil || 0)
                    };
                } else {
                    mergedMap[key]["Matrah"] += parseFloat(detay.Matrah || 0);
                    mergedMap[key]["KDV Tutarı"] += parseFloat(detay.KDVTutari || 0);
                    mergedMap[key]["Toplam Tutar"] += parseFloat(detay.Tutar_KDVDahil || 0);
                }
            });
        } else {
            const key = `${r.fis_no}_${r.KDVOrani || 0}_${r.kategori || "Genel"}_${r.tarih}`;
            if (!mergedMap[key]) {
                mergedMap[key] = {
                    ...r,
                    "Açıklama": r.kategori || "Genel",
                    "Matrah": parseFloat(r.toplam_tutar || 0),
                    "KDV Oranı": 0,
                    "KDV Tutarı": 0,
                    "Toplam Tutar": parseFloat(r.toplam_tutar || 0)
                };
            }
        }
    }

    let finalRows = Object.values(mergedMap);
    finalRows.sort((a, b) => new Date(a["Tarih"]) - new Date(b["Tarih"]));

    const sheetRows = finalRows.map(r => ({
        values: [
            { userEnteredValue: { stringValue: "" } },
            { userEnteredValue: { stringValue: formatDateTR(r["Tarih"]) } },
            { userEnteredValue: { stringValue: r["Fiş No"] || "" } },
            { userEnteredValue: { stringValue: r["İşletme"] || "" } },
            { userEnteredValue: { stringValue: r["Açıklama"] || "" } },
            { userEnteredValue: { numberValue: Number(r["Matrah"]) } },
            { userEnteredValue: { numberValue: Number(r["KDV Oranı"]) } },
            { userEnteredValue: { numberValue: Number(r["KDV Tutarı"]) } },
            { userEnteredValue: { numberValue: Number(r["Toplam Tutar"]) } },
            { userEnteredValue: { stringValue: r["Görsel"] || "" } }
        ]
    }));

    // 4. PAYLOAD OLUŞTUR
    const requests = [
        {
            updateCells: {
                range: { sheetId: newSheetId, startRowIndex: 1, endRowIndex: 3, startColumnIndex: 4, endColumnIndex: 5 }, 
                rows: [{ values: [{ userEnteredValue: { stringValue: headerText } }] }],
                fields: "userEnteredValue"
            }
        },
        {
            updateCells: {
                range: { sheetId: newSheetId, startRowIndex: 2, endRowIndex: 3, startColumnIndex: 3, endColumnIndex: 4 }, 
                rows: [{ values: [{ userEnteredValue: { stringValue: realUserName } }] }], 
                fields: "userEnteredValue"
            }
        },
        {
            updateCells: {
                range: { sheetId: newSheetId, startRowIndex: 2, endRowIndex: 3, startColumnIndex: 8, endColumnIndex: 9 }, 
                rows: [{ values: [{ userEnteredValue: { stringValue: evrakNo } }] }],
                fields: "userEnteredValue"
            }
        }
    ];

    if (sheetRows.length > 0) {
        requests.push({
            updateCells: {
                range: { sheetId: newSheetId, startRowIndex: 13, startColumnIndex: 0 }, 
                rows: sheetRows,
                fields: "userEnteredValue"
            }
        });
    }

    // Dosya ID'si
    // Rapor Dosyası Oluştur düğümünün adını kontrol et (Genelde 'Rapor Dosyası Oluştur' dur)
    let targetSpreadsheetId;
    try {
        const fileNode = $('Rapor Dosyası Oluştur').first() || $('Rapor Dosyası Oluştur1').first();
        targetSpreadsheetId = fileNode.json.id;
    } catch(e) {
        targetSpreadsheetId = "ID_BULUNAMADI";
    }

    return { 
        json: { 
            updatePayload: { requests }, 
            targetSpreadsheetId: targetSpreadsheetId
        } 
    };

} catch (error) {
    throw new Error(error.message);
}

// 1. Gelen verileri al
const receipts = $input.all().map(item => item.json);

// --- YARDIMCI FONKSİYONLAR ---
function safeDateFormatter(dateStr) {
    if (!dateStr) return null;
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return null;
    try { return d.toISOString().split('T')[0]; } catch (e) { return null; }
}

function cleanString(str) {
    if (!str) return "";
    return str.toString().toLocaleUpperCase('tr-TR').replace(/\s+/g, '').replace(/[^A-Z0-9ĞÜŞİÖÇ]/g, ""); 
}

// --- ANA MANTIK ---
const groups = {};        
const duplicates = [];    
const seenKeys = new Set(); 

for (const receipt of receipts) {

    // 1. Mükerrer Kontrol Anahtarı (Tarih + Tutar + Fiş No)
    const dateKey = safeDateFormatter(receipt.tarih) || safeDateFormatter(receipt.created_at) || "TarihYok";
    const amountKey = parseFloat(receipt.toplam_tutar || 0).toFixed(2);
    const fisNoKey = cleanString(receipt.fis_no);

    const uniqueKey = `${dateKey}_${amountKey}_${fisNoKey}`;

    // 2. Kontrol Et: Daha önce gördük mü?
    if (seenKeys.has(uniqueKey)) {
        // EVET -> Bu mükerrerdir, duplicates listesine at.
        duplicates.push({
            id: receipt.id,
            fis_no: receipt.fis_no,
            durum: "Mükerrer",
            description: "Aynı tarih, tutar ve fiş numarasına sahip kayıt bulundu."
        });
        continue; // Aşağıdaki gruplama işlemine sokma, döngüden çık.
    } else {
        seenKeys.add(uniqueKey);
    }

    // --- BURAYA GELENLER ARTIK BENZERSİZ (UNIQUE) FİŞLERDİR ---

    // 3. Gruplama (Kullanıcı + Kart + Proje)
    const userId = receipt.user_id || 'Belirsiz';
    const cardLast4 = receipt.kart_son_4 || 'Nakit/Diğer';
    const project = receipt.proje || 'Genel';
    const groupKey = `${userId}_${cardLast4}_${project}`;

    if (!groups[groupKey]) {
        groups[groupKey] = {
            // Bu "meta" bilgisi (Başlıklar için)
            meta: { 
                kullanici: userId, 
                kart: cardLast4, 
                proje: project,
                // Sayfa ismi (Max 30 karakter)
                sheetName: `${project.substring(0,10)} - ${cardLast4}`.substring(0,30)
            },
            // Bu "rows" bilgisi (Fişlerin listesi)
            rows: [] 
        };
    }

    // Fişi ilgili grubun paketine ekle (Detaylarıyla birlikte)
    groups[groupKey].rows.push({
        ...receipt,
        'Tarih': dateKey,
        'Fiş No': receipt.fis_no,
        'İşletme': receipt.isletme_adi,
        'Ödeme Tipi': receipt.odeme_tipi,
        'Görsel': receipt.gorsel_url,
        'Açıklama': receipt.kategori || 'Genel',
        'Matrah': parseFloat(receipt.toplam_tutar || 0),
        'KDV Oranı': 0, // Varsayılan (Yazma düğümünde detaylandırılacak)
        'KDV Tutarı': 0,
        'Toplam Tutar': parseFloat(receipt.toplam_tutar || 0),
        'ocr_detaylari': receipt.ocr_detaylari // OCR detaylarını koru
    });
}

// 4. ÇIKTIYI HAZIRLA
// İki ayrı liste döndürüyoruz: 
// a) report_batches: Raporlanacak gruplar (Paketler)
// b) duplicates: Mükerrer olanlar (Etiketlenecekler)

// Grupları diziye çevir ve her grubu kendi içinde tarihe göre sırala
const reportBatches = Object.values(groups).map(g => {
    g.rows.sort((a, b) => new Date(a.Tarih) - new Date(b.Tarih));
    return g;
});

return {
    json: {
        report_batches: reportBatches, // Rapor akışına gidecek
        duplicates: duplicates,        // Mükerrer akışına gidecek
        stats: {
            total: receipts.length,
            unique: reportBatches.reduce((acc, g) => acc + g.rows.length, 0),
            duplicate: duplicates.length
        }
    }
};

// Gelen item'ı al
const item = $input.first();

// Eğer item'da report_batches varsa (yani raporlama node'undan geliyorsa)
if (item.json.report_batches && Array.isArray(item.json.report_batches)) {
    const batches = item.json.report_batches;

    console.log('📦 Toplam Grup:', batches.length);

    // Her grubu ayrı item olarak döndür
    return batches.map((batch, index) => {
        console.log(`✅ Grup ${index + 1}:`, batch.meta.sheetName);
        return { json: batch };
    });
}

// Eğer direkt grup verisi geliyorsa (zaten array ise)
const items = $input.all();
console.log('📋 Gelen item sayısı:', items.length);
return items;

// Node Adı: "Debug - Grup Sayısı"

// GÜVENLİ VERİ ALMA
const inputData = $input.first().json;
const batches = inputData.report_batches || [];

console.log('📦 TOPLAM GRUP SAYISI:', batches.length);

if (batches.length === 0) {
    console.log('⚠️ UYARI: Hiç grup bulunamadı!');
    return $input.all();
}

batches.forEach((batch, index) => {
    console.log(`Grup ${index + 1}:`, {
        kullanici: batch.meta?.kullanici || 'N/A',
        kart: batch.meta?.kart || 'N/A',
        proje: batch.meta?.proje || 'N/A',
        satirSayisi: batch.rows?.length || 0
    });
});

return $input.all();

// ----------------------------------------------------------------
// FİŞ ID'LERİNİ HAZIRLA (İsim Düzeltmeli)
// ----------------------------------------------------------------

let rows = [];

try {
    // 1. YÖNTEM: Senin düğüm isminle (Gurupları...)
    if ($node["Gurupları Döngüye Al"] && $node["Gurupları Döngüye Al"].json) {
        rows = $node["Gurupları Döngüye Al"].json.rows;
    }
    // 2. YÖNTEM: Belki sonunda "1" vardır (Gurupları Döngüye Al1)
    else if ($node["Gurupları Döngüye Al1"] && $node["Gurupları Döngüye Al1"].json) {
        rows = $node["Gurupları Döngüye Al1"].json.rows;
    }
    // 3. YÖNTEM: Modern Erişim ($ notation)
    else {
        rows = $('Gurupları Döngüye Al').item.json.rows;
    }
} catch (error) {
    // Eğer veri bulunamazsa, akışı kırmamak için boş dizi tanımla
    // console.log("Veri çekme hatası: " + error.message);
    rows = [];
}

// Güvenlik Kontrolü: Rows yoksa boş dön
if (!rows || !Array.isArray(rows)) {
    return [];
}

// Her bir fiş için ayrı bir çıktı (item) oluştur
// Böylece sonraki Supabase düğümü her biri için ayrı ayrı çalışır
return rows.map(row => ({
    json: {
        id: row.id
    }
}));

// Gruptaki tüm güncellemeler bitti.
// Ana döngüye sadece tek bir "Devam Et" sinyali gönderiyoruz.
return [ $input.first() ];
